{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a graph embedding/topological mapping problem where we need to represent a color adjacency graph using a 2D grid while maximizing empty cells. I will split this into graph analysis and grid layout optimization.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract a graph where each node is a color (1 to M) and an edge exists between two nodes if their corresponding colors are adjacent in the input grid. Identify the adjacency list and the connectivity of each color component."
    },
    {
      "label": "grid_layout_optimizer",
      "instructions": "Given a graph of colors and their adjacency requirements, design an algorithm to place these colors on a 50x50 grid. Each color must occupy at least one cell, all cells of the same color must be connected, and two colors can only be adjacent if they have an edge in the graph. The goal is to minimize the number of cells used by colors to maximize the number of 0 cells."
    }
  ],
  "synthesis_brief": "Combine the adjacency graph from the first helper with the layout strategy from the second helper to generate a valid 50x50 grid in main.py that preserves all color adjacencies and connectivity while maximizing empty cells."
}

